from dataclasses import dataclass

@dataclass
class ErrorResponse:
    error:      str        # "Bad Request [errorRef=a3f2c1d0...]"
    error_type: str        # "axis2_payload_error"
    suggestions: list[str] # ["Check x-axis2-payloadTemplate in catalog"]

import httpx import json from mcp.server import Server from mcp.server.stdio import stdio_server from mcp.types import Tool, TextContent
BASE_URL = "https://your-axis2-server/services" server = Server("axis2-mcp") _token = None
async def login(email: str, password: str) -> str: async with httpx.AsyncClient() as c: r = await c.post( f"{BASE_URL}/loginService/doLogin", json={"doLogin": [{"arg0": {"email": email, "credentials": password}}]} ) return r.json()["response"]["token"]
async def call_service(service: str, op: str, params: dict) -> dict: async with httpx.AsyncClient() as c: r = await c.post( f"{BASE_URL}/{service}/{op}", json={op: [{"arg0": params}]}, headers={"Authorization": f"Bearer {_token}"} ) return r.json()
@server.list_tools() async def list_tools() -> list[Tool]: # Fetch live from catalog — honors Cache-Control: no-cache async with httpx.AsyncClient() as c: catalog = (await c.get(f"{BASE_URL}/../openapi-mcp.json")).json() return [ Tool(name=t["name"], description=t["description"], inputSchema=t["inputSchema"]) for t in catalog["tools"] ]
@server.call_tool() async def call_tool(name: str, arguments: dict) -> list[TextContent]: # Resolve service name from catalog endpoint field # then delegate to call_service() ...
